import { useEffect, useState } from 'react';

const NAV_LINKS = ['About', 'Skills', 'Projects', 'Experience', 'Contact'];

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const [active, setActive]   = useState('');

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 40);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  return (
    <nav
      style={{
        position: 'fixed', top: 0, left: 0, right: 0, zIndex: 100,
        height: '64px', display: 'flex', alignItems: 'center',
        justifyContent: 'space-between', padding: '0 2rem',
        background: scrolled ? 'rgba(8,12,20,0.92)' : 'transparent',
        backdropFilter: scrolled ? 'blur(12px)' : 'none',
        borderBottom: scrolled ? '1px solid var(--border)' : 'none',
        transition: 'all 0.3s ease',
      }}
    >
      {/* Logo */}
      <a href="#about" style={{ fontFamily: 'Syne', fontWeight: 800, fontSize: '1.2rem', letterSpacing: '-0.03em' }}>
        <span style={{ color: 'var(--accent)' }}>S</span>anjay
        <span style={{ color: 'var(--accent)' }}>.S</span>
      </a>

      {/* Links */}
      <div style={{ display: 'flex', gap: '2rem' }}>
        {NAV_LINKS.map((link) => (
          <a
            key={link}
            href={`#${link.toLowerCase()}`}
            onClick={() => setActive(link)}
            style={{
              fontSize: '0.82rem', fontWeight: 500, letterSpacing: '0.06em',
              textTransform: 'uppercase',
              color: active === link ? 'var(--accent)' : 'var(--muted)',
              transition: 'color 0.2s',
            }}
            onMouseEnter={(e) => (e.target.style.color = 'var(--text)')}
            onMouseLeave={(e) => (e.target.style.color = active === link ? 'var(--accent)' : 'var(--muted)')}
          >
            {link}
          </a>
        ))}
      </div>
    </nav>
  );
}
